import{_ as t,c as r,o,ag as a}from"./chunks/framework.DVUBUV_u.js";const m=JSON.parse('{"title":"Export Collection","description":"","frontmatter":{},"headers":[],"relativePath":"network/export.md","filePath":"network/export.md"}'),s={name:"network/export.md"};function n(i,e,l,d,h,c){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="export-collection" tabindex="-1">Export Collection <a class="header-anchor" href="#export-collection" aria-label="Permalink to &quot;Export Collection&quot;">​</a></h1><p>On the <strong>Network</strong> tab, captured requests can be saved as a <strong>Postman collection</strong> file (an API description format compatible with Postman and many other clients). This is useful for replaying flows, sharing them with teammates, or importing them into a separate testing tool.</p><p>What appears in the list and possible data visibility limitations are described in <a href="/docs/network/general.html">Working with requests</a>.</p><hr><h2 id="where-to-find-the-command" tabindex="-1">Where to find the command <a class="header-anchor" href="#where-to-find-the-command" aria-label="Permalink to &quot;Where to find the command&quot;">​</a></h2><p><strong>Export Collection</strong> is located on the <strong>Network</strong> toolbar (next to search and filters; on narrow layouts it may appear in a different header section, but the action remains the same).</p><p>The tooltip indicates that the <strong>currently filtered</strong> set of requests will be exported.</p><p>The button remains <strong>disabled</strong> while the filtered list is empty.</p><hr><h2 id="what-gets-exported" tabindex="-1">What gets exported <a class="header-anchor" href="#what-gets-exported" aria-label="Permalink to &quot;What gets exported&quot;">​</a></h2><p>The file contains <strong>only rows currently visible</strong> in the table with <strong>Search</strong> and active search modes applied (path, method, status code, keys and values inside bodies, and so on). This is not necessarily the full request history: active filters restrict what enters the collection.</p><p>For each included row, a separate request is created in the collection with:</p><ul><li><strong>method</strong> and <strong>URL</strong> (including address components and query string when present);</li><li><strong>request headers</strong> stored by the inspector (pseudo-headers starting with <code>:</code> are omitted; for <strong>multipart</strong> bodies the content-type header may be intentionally skipped to avoid conflicts with Postman <strong>form-data</strong> mode);</li><li><strong>request body</strong> when captured: raw text (including JSON syntax hints where applicable) or <strong>form-data</strong> fields, including file-part markers (binary files themselves are not attached — only names or placeholders are exported, as is typical when no real files are available).</li></ul><p><strong>Server responses</strong> are <strong>not included</strong> — the export contains only the description of <strong>outgoing</strong> requests suitable for replay from a client.</p><p>Collection item names follow the short request label shown in the Network list.</p><hr><h2 id="saved-file" tabindex="-1">Saved file <a class="header-anchor" href="#saved-file" aria-label="Permalink to &quot;Saved file&quot;">​</a></h2><p>After clicking <strong>Export Collection</strong>, the browser offers a <strong>JSON</strong> file download with a Postman-style filename (spaces in the default title are usually replaced with underscores).</p><p>The file can be imported into <strong>Postman</strong> or opened in any editor to inspect its structure.</p><hr><h2 id="caveats" tabindex="-1">Caveats <a class="header-anchor" href="#caveats" aria-label="Permalink to &quot;Caveats&quot;">​</a></h2><ul><li>Only <strong>headers and bodies the inspector was able to read</strong> are included in the export (CORS limitations, truncated bodies, opaque binary content, and similar restrictions may affect output).</li><li>Rows with <strong>network errors</strong> or partial data may still appear in the export if they remain visible after filtering — validate requests before reuse.</li><li><strong>Replaying</strong> requests from Postman may differ from browser behavior because of cookies, tokens, environment settings, and headers automatically added by the browser — manual adjustment after import may be required.</li></ul><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/network/general.html">Working with requests</a></li><li><a href="/docs/network/traffic.html">Traffic interception</a></li></ul>',25)])])}const f=t(s,[["render",n]]);export{m as __pageData,f as default};
